-- Desktop Environment Script for OpenComputers\n\nlocal component = require("component")\nlocal event = require("event")\nlocal os = require("os")\nlocal gpu = component.gpu\nlocal term = require("term")\n\n-- Set the resolution of the desktop window\ngpu.setResolution(80, 25)\n\n-- Function to clear the screen\nlocal function clearScreen()\n    gpu.fill(1, 1, 80, 25, " ")\nend\n\n-- Function to draw a desktop background\nlocal function drawBackground()\n    clearScreen()\n    gpu.setForeground(0xFFFFFF)  -- White text\n    gpu.set(1, 1, "Welcome to the Desktop Environment!")\n    gpu.set(1, 3, "[1] Open Program\n[2] Shutdown")\nend\n\n-- Main function to run the desktop environment\nlocal function runDesktop()\n    drawBackground()\n    while true do\n        local e = {event.pull()}\n        if e[1] == "key_down" then\n            if e[4] == 1 then  -- If '1' is pressed\n                gpu.set(1, 5, "Opening program...")\n            elseif e[4] == 2 then  -- If '2' is pressed\n                gpu.set(1, 5, "Shutting down...")\n                os.exit()\n            end\n        end\n    end\nend\n\n-- Start the desktop environment\nrunDesktop()